def run_rpc_demo():
    """Demonstrate RPC-style task execution with reply."""
    # Set up callback queue
    connection = pika.BlockingConnection(
        pika.ConnectionParameters(host='localhost', port=5672)
    )
    channel = connection.channel()

    result = channel.queue_declare(queue='', exclusive=True)
    callback_queue = result.method.queue

    responses = {}

    def on_response(ch, method, properties, body):
        response = json.loads(body.decode('utf-8'))
        responses[properties.correlation_id] = response
        logger.info(f"RPC Response received: {response}")

    channel.basic_consume(
        queue=callback_queue,
        on_message_callback=on_response,
        auto_ack=True
    )

    # Publish task with reply_to
    publisher = TaskPublisher(queue_name='task_queue')
    publisher.connect()
    publisher.setup()

    correlation_id = str(uuid.uuid4())
    publisher.publish_task(
        task_name='process_data',
        task_data={
            'dataset': 'inventory_2024',
            'operation': 'count'
        },
        correlation_id=correlation_id,
        reply_to=callback_queue
    )

    print(f"Published RPC task with correlation_id: {correlation_id}")
    print("Waiting for response...")

    # Wait for response with timeout
    timeout = 30
    start = time.time()
    while correlation_id not in responses and time.time() - start < timeout:
        connection.process_data_events(time_limit=1)

    if correlation_id in responses:
        print(f"RPC Result: {responses[correlation_id]}")
    else:
        print("RPC timed out.")

    publisher.close()
    connection.close()


